 12	export const addVolume = (vol: volData) => {
 13	  const {
 14	    instanceType,
 15	    iso,
 16	    name,
 17	    preference,
 18	    project,
 19	    pvcName,
 20	    registryURL,
 21	    sourceType,
 22	    uploadImage,
 23	    volName,
 24	  } = vol;
 25	  cy.get('#tab-modal').within(() => {
 26	    cy.wait(3000); // give seconds to wait for modal loaded
 27	    switch (sourceType) {
 28	      case 'Upload': {
 29	        cy.dropFile(uploadImage, uploadImage.split('/').pop(), iView.upload);
 30	        if (iso) {
 31	          cy.get('input[id="iso-checkbox"]').check();
 32	        }
 33	        break;
 34	      }
 35	      case 'Volume': {
 36	        cy.contains(iView.toggleText, 'Volume').click();
 37	        cy.get('.pf-v6-c-menu__list-item').eq(1).click();
 38	        cy.contains('.pf-v6-c-menu-toggle__text', '--- Select Volume project ---').click();
 39	        cy.get(`[data-test-id="select-option-${project}"]`).click();
 40	        cy.contains('.pf-v6-c-menu-toggle__text', '--- Select Volume name ---').click();
 41	        cy.get(`[data-test-id="${pvcName}"]`).click();
 42	        break;
 43	      }
 44	      case 'Volume snapshot': {
 45	        cy.contains(iView.toggleText, 'Volume').click();
 46	        cy.contains(iView.menuItemText, 'Volume snapshot').click();
 47	        cy.get('button[placeholder="--- Select VolumeSnapshot project ---"]').click();
 48	        cy.get('input[placeholder="--- Select VolumeSnapshot project ---"]').type('os-images');
 49	        cy.byLegacyTestID(index.OS_IMAGES_NS).click();
 50	        cy.wait(2000);
 51	        cy.contains(iView.toggleText, '--- Select VolumeSnapshot name ---').click();
 52	        cy.byButtonText(volName).click();
 53	        break;
 54	      }
 55	      case 'Registry': {
 56	        cy.contains(iView.toggleText, 'Volume').click();
 57	        cy.contains(iView.menuItemText, 'Registry').click();
 58	        cy.get(iView.registryURL)
 59	          .type(registryURL, { delay: 1000 })
 60	          .should('have.value', registryURL);
 61	        cy.get(iView.cronExp).type('0 0 * * 2');
 62	        break;
 63	      }
 64	    }
 65	    cy.wait(2000); // give a bit more time for volume present in the modal
 66	    cy.get(iView.volumeName).type(name);
 67	    // select preference
 68	    cy.contains(iView.toggleText, iView.selectPreferenceText).click();
 69	    cy.get(iView.searchPreference).type(preference);
 70	    cy.get(iView.preferenceValue(preference)).click();
 71	    // select instanceType
 72	    cy.contains(iView.toggleText, iView.selectInstanceText).click();
 73	    cy.contains(iView.menuItemText, 'Red Hat provided').click();
 74	    cy.contains(iView.menuItemText, 'U series').click();
 75	    if (instanceType) {
 76	      cy.contains(iView.menuItemText, instanceType).click();
 77	    } else {
 78	      cy.contains(iView.menuItemText, 'nano:').click();
 79	    }
 80	    cy.get(iView.description).scrollIntoView().type(`Test volume from ${sourceType}`); // file description
 81	    cy.clickSaveBtn();
 82	    cy.wait(60000);
 83	    cy.contains(iView.modalTitle, iView.modalTitleText).should('not.exist');
 84	  });
 85	};
